import React, { useState, useContext } from 'react';
import { useNavigate } from 'react-router-dom';
import { AppContext } from '../App';
import { configuracaoEmpresa, colaboradores as mockColaboradores } from '../data/mockData';

type ViewMode = 'login' | 'register' | 'confirm' | 'forgot';

const Login: React.FC = () => {
  const navigate = useNavigate();
  const { 
    setIsAuthenticated, setColaboradores, setEmpresa, setUser, 
    setIsConfigured, setEmpresas, setEmpresaId 
  } = useContext(AppContext);

  const [mode, setMode] = useState<ViewMode>('login');
  const [email, setEmail] = useState('admin@salya.com');
  const [password, setPassword] = useState('admin123');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [name, setName] = useState('');
  const [confirmCode, setConfirmCode] = useState('');
  const [showPassword, setShowPassword] = useState(false);
  const [errorString, setErrorString] = useState('');

  const executeLogin = (userEmail: string, userName: string) => {
    setIsAuthenticated(true);
    setUser({ email: userEmail, name: userName });

    if (userEmail === 'admin@salya.com') {
      const empresaComId = { ...configuracaoEmpresa, id: 1 };
      setEmpresas([empresaComId]);
      setEmpresaId(1);
      setEmpresa(empresaComId);
      setColaboradores(mockColaboradores.map(c => ({ ...c, empresaId: 1 })));
      setIsConfigured(true);
      navigate('/processamento');
    } else {
      setEmpresas([]);
      setEmpresaId(null);
      setEmpresa(null);
      setColaboradores([]);
      setIsConfigured(false);
      navigate('/configuracoes');
    }
  };

  const handleLogin = (e: React.FormEvent) => {
    e.preventDefault();
    if (email && password) {
      executeLogin(email, 'Administrador');
    }
  };

  const handleRegister = (e: React.FormEvent) => {
    e.preventDefault();
    if (password !== confirmPassword) {
      setErrorString('As senhas não coincidem.');
      return;
    }
    if (name && email && password) {
      setMode('confirm');
    }
  };

  const handleConfirm = (e: React.FormEvent) => {
    e.preventDefault();
    if (confirmCode) {
      setMode('login');
      setEmail('');
      setPassword('');
      setName('');
      setConfirmPassword('');
      setConfirmCode('');
    }
  };

  const handleForgotPassword = (e: React.FormEvent) => {
    e.preventDefault();
    if (email) {
      setMode('login');
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center p-4 bg-slate-50 dark:bg-slate-950">
      <div className="flex h-auto w-full max-w-[1100px] flex-col md:flex-row bg-white dark:bg-slate-900 rounded-[32px] shadow-2xl overflow-hidden border border-slate-100 dark:border-slate-800">
        {/* Left Side - The Premium Branding Section */}
        <div className="hidden md:flex md:w-1/2 relative bg-primary items-center justify-center p-12 overflow-hidden">
          <div className="absolute inset-0 opacity-20 bg-cover bg-center" style={{ backgroundImage: 'url("https://images.unsplash.com/photo-1497366216548-37526070297c?w=800")' }}></div>
          <div className="absolute inset-0 bg-gradient-to-br from-primary via-primary/95 to-slate-900/60"></div>

          <div className="relative z-10 flex flex-col gap-10 text-white w-full max-w-sm font-sans">
            <div className="flex items-center gap-4">
              <img src="/logo.png" alt="SALYA Logo" className="w-16 h-16 object-contain bg-white/10 p-3 rounded-2xl backdrop-blur-md border border-white/20 shadow-2xl" />
              <div>
                <h1 className="text-3xl font-black tracking-tighter uppercase leading-none">SALYA</h1>
                <p className="text-[10px] font-black uppercase tracking-[6px] opacity-60 mt-1">Smarter Payroll</p>
              </div>
            </div>

            <div className="space-y-4">
              <h2 className="text-4xl font-black leading-tight uppercase tracking-widest">Processamento<br/>Salarial Digital</h2>
              <div className="h-1 w-20 bg-white/40 rounded-full"></div>
            </div>
          </div>
        </div>

        {/* Right Side - Forms */}
        <div className="w-full md:w-1/2 p-8 md:p-16 flex flex-col justify-center bg-white dark:bg-slate-900 font-sans">
          <div className="md:hidden flex items-center gap-3 mb-12 justify-center">
            <img src="/logo.png" alt="SALYA Logo" className="w-12 h-12 object-contain" />
            <h1 className="text-2xl font-black tracking-tight text-primary uppercase">SALYA</h1>
          </div>

          {mode === 'login' && (
            <div className="animate-in fade-in slide-in-from-right-4 duration-500">
              <div className="mb-10 text-left">
                <h2 className="text-3xl font-black text-slate-900 dark:text-white uppercase tracking-tight">Iniciar Sessão</h2>
                <p className="text-xs font-bold text-slate-400 mt-2 uppercase tracking-[2px]">Aceda à sua plataforma de gestão</p>
              </div>

              <form className="space-y-6" onSubmit={handleLogin}>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-[3px]">E-mail de Acesso</label>
                  <input
                    type="email"
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    className="w-full px-6 py-4 bg-slate-50 dark:bg-slate-800 border-none rounded-2xl outline-none focus:ring-2 focus:ring-primary font-bold dark:text-white transition-all text-sm"
                    required
                  />
                </div>

                <div className="space-y-2 relative">
                  <div className="flex justify-between items-center mb-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-[3px]">Palavra-passe</label>
                  </div>
                  <input
                    type={showPassword ? 'text' : 'password'}
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    className="w-full px-6 py-4 bg-slate-50 dark:bg-slate-800 border-none rounded-2xl outline-none focus:ring-2 focus:ring-primary font-bold dark:text-white transition-all text-sm"
                    required
                  />
                  <button
                    type="button"
                    onClick={() => setShowPassword(!showPassword)}
                    className="absolute right-4 top-[38px] text-slate-400 hover:text-primary transition-colors"
                  >
                    <span className="material-symbols-outlined text-lg">{showPassword ? 'visibility_off' : 'visibility'}</span>
                  </button>
                </div>

                <div className="flex justify-end">
                  <button type="button" onClick={() => setMode('forgot')} className="text-[10px] font-black text-primary uppercase tracking-widest hover:underline decoration-2 text-right">Esqueceu a senha?</button>
                </div>

                <button type="submit" className="w-full bg-primary hover:bg-primary/90 text-white font-black py-5 rounded-2xl shadow-2xl shadow-primary/20 transition-all flex items-center justify-center gap-3 uppercase tracking-[4px] text-xs">
                  Entrar no Painel
                </button>

                <p className="mt-8 text-center text-[10px] font-black text-slate-400 uppercase tracking-widest">
                  Ainda não tem conta? <button type="button" onClick={() => setMode('register')} className="text-primary hover:underline font-black">Criar Agora</button>
                </p>
              </form>
            </div>
          )}

          {mode === 'register' && (
            <div className="animate-in fade-in slide-in-from-right-4 duration-500">
              <div className="mb-8">
                <h2 className="text-3xl font-black text-slate-900 dark:text-white uppercase tracking-tight">Criar Conta</h2>
                <p className="text-xs font-bold text-slate-400 mt-2 uppercase tracking-[2px]">Junte-se ao Ecossistema SALYA</p>
                {errorString && <p className="text-red-500 text-[10px] font-black uppercase mt-3">{errorString}</p>}
              </div>

              <form className="space-y-4" onSubmit={handleRegister}>
                <div className="space-y-1.5"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Nome do Gestor</label><input type="text" value={name} onChange={(e) => setName(e.target.value)} className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-800 rounded-2xl outline-none focus:ring-2 focus:ring-primary font-bold dark:text-white text-sm" required /></div>
                <div className="space-y-1.5"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">E-mail Corporativo</label><input type="email" value={email} onChange={(e) => setEmail(e.target.value)} className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-800 rounded-2xl outline-none focus:ring-2 focus:ring-primary font-bold dark:text-white text-sm" required /></div>
                <div className="grid grid-cols-2 gap-4">
                  <div className="space-y-1.5"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Definir Senha</label><input type="password" value={password} onChange={(e) => setPassword(e.target.value)} className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-800 rounded-2xl outline-none focus:ring-2 focus:ring-primary font-bold dark:text-white text-sm" required /></div>
                  <div className="space-y-1.5"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Confirmar</label><input type="password" value={confirmPassword} onChange={(e) => setConfirmPassword(e.target.value)} className="w-full px-5 py-4 bg-slate-50 dark:bg-slate-800 rounded-2xl outline-none focus:ring-2 focus:ring-primary font-bold dark:text-white text-sm" required /></div>
                </div>

                <button type="submit" className="w-full bg-primary hover:bg-primary/90 text-white font-black py-5 mt-6 rounded-2xl shadow-xl shadow-primary/20 transition-all uppercase tracking-[4px] text-xs">
                  Criar Conta SALYA
                </button>

                <p className="mt-8 text-center text-[10px] font-black text-slate-400 uppercase tracking-widest">
                  Já tem uma conta? <button type="button" onClick={() => setMode('login')} className="text-primary hover:underline font-black">Fazer Login</button>
                </p>
              </form>
            </div>
          )}

          {mode === 'confirm' && (
            <div className="animate-in zoom-in-95 duration-500">
              <div className="text-center mb-10">
                <h2 className="text-2xl font-black uppercase text-slate-900 dark:text-white tracking-tight">Verificação Individual</h2>
                <p className="text-[10px] text-slate-400 font-bold mt-2 uppercase tracking-[3px]">Código de segurança enviado por e-mail</p>
              </div>

              <form className="space-y-8" onSubmit={handleConfirm}>
                <input
                  type="text"
                  maxLength={6}
                  value={confirmCode}
                  onChange={(e) => setConfirmCode(e.target.value)}
                  className="w-full text-center text-5xl font-black tracking-[15px] py-8 bg-slate-50 dark:bg-slate-800 rounded-[32px] outline-none focus:ring-2 focus:ring-primary dark:text-white font-mono shadow-inner"
                  placeholder="000000"
                  required
                />
                <button type="submit" className="w-full bg-primary hover:bg-primary/90 text-white font-black py-5 rounded-2xl shadow-2xl shadow-primary/20 uppercase tracking-[4px] text-xs">
                  Confirmar Acesso
                </button>
              </form>
            </div>
          )}

          {mode === 'forgot' && (
            <div className="animate-in fade-in duration-500">
               <div className="text-center mb-10">
                <h2 className="text-2xl font-black uppercase text-slate-900 dark:text-white tracking-tight">Recuperar Senha</h2>
                <p className="text-[10px] text-slate-400 font-bold mt-2 uppercase tracking-[3px]">Introduza o seu e-mail de registo</p>
              </div>
              <form className="space-y-6" onSubmit={handleForgotPassword}>
                <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase tracking-widest">E-mail</label><input type="email" value={email} onChange={(e) => setEmail(e.target.value)} className="w-full px-6 py-4 bg-slate-50 dark:bg-slate-800 rounded-2xl outline-none focus:ring-2 focus:ring-primary font-bold dark:text-white text-sm" required /></div>
                <button type="submit" className="w-full bg-primary hover:bg-primary/90 text-white font-black py-5 rounded-2xl shadow-xl shadow-primary/20 uppercase tracking-[4px] text-xs">Enviar Link de Recuperação</button>
                <button type="button" onClick={() => setMode('login')} className="w-full text-center text-[10px] font-black text-slate-400 uppercase tracking-widest hover:text-primary transition-colors">Voltar ao Login</button>
              </form>
            </div>
          )}

          <div className="mt-12 pt-8 border-t border-slate-50 dark:border-slate-800 text-center">
             <p className="text-[9px] font-black text-slate-300 uppercase tracking-[6px]">SALYA Ecosystem © 2026</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Login;
